const j = $('03j - Enriquecer com Histórico').item.json;
const lista = j.lista_protocolos || [];
const nome = $('01 - Webhook WhatsApp3').item.json.body.data.pushName || 'Cidadão';

if (lista.length === 0) {
  return [{ json: {
    message: `Olá, ${nome}! Não encontrei chamados anteriores para consultar. Se quiser abrir um novo, descreva o problema.`,
    lista_protocolos: []
  }}];
}

let msg = `Olá, ${nome}! 📋 Você tem *${lista.length}* chamado(s):\n\n`;
lista.forEach((item, i) => {
  const status = item.status || item.situacao || 'Em andamento';
  const cat = item.categoria || item.tipo || '';
  msg += `*${i + 1}.* ${item.protocolo}${cat ? ' — ' + cat : ''} _(${status})_\n`;
});
msg += `\nDigite o *número* do chamado que deseja consultar.`;

return [{ json: { message: msg, lista_protocolos: lista } }];

const listaJson = $json.value;
let lista = [];
try {
  lista = listaJson ? JSON.parse(listaJson) : [];
} catch(e) {
  lista = [];
}

const texto = ($('03j - Enriquecer com Histórico').item.json.texto_cidadao || '').trim();

// Código ZEL- direto
const zelMatch = texto.match(/ZEL-\d{8}-[A-Z0-9]+/i);
if (zelMatch) {
  return [{ json: { protocolo_consulta: zelMatch[0].toUpperCase() } }];
}

// Número da lista (1, 2, 3...)
const numMatch = texto.match(/\b([1-9]\d?)\b/);
if (numMatch && lista.length > 0) {
  const idx = parseInt(numMatch[1]) - 1;
  if (idx >= 0 && idx < lista.length && lista[idx]?.protocolo) {
    return [{ json: { protocolo_consulta: lista[idx].protocolo } }];
  }
}

// Fallback: primeiro da lista
if (lista.length > 0 && lista[0]?.protocolo) {
  return [{ json: { protocolo_consulta: lista[0].protocolo } }];
}

const ultimoProtocolo = $('03j - Enriquecer com Histórico').item.json.ultimo_protocolo;
return [{ json: { protocolo_consulta: ultimoProtocolo || null } }];

const data = $input.first().json;

if (!data || !data.ocorrencia) {
/**
   const n05Executed = $('05 - Parse JSON da IA3').isExecuted;
  const protocolo = (n05Executed ? ($('05 - Parse JSON da IA3').item.json.protocolo_consulta || null) : null)
    || $('03j - Enriquecer com Histórico').item.json.ultimo_protocolo
    || 'Não encontrado';

 */
  return [{
    json: {
      ocorrencia: {
        protocolo,
        status: 'NAO_ENCONTRADO',
        categoria: '-',
        ultimo_log: null,
        total_atualizacoes: 0,
        updated_at: null
      }
    }
  }];
}

return [{ json: data }];

let srtContent = '';
const resp = $input.first().json;

if (typeof resp === 'string') {
  srtContent = resp;
} else if (resp.srt) {
  srtContent = resp.srt;
} else if (resp.text) {
  srtContent = resp.text;
} else if (resp.transcription) {
  srtContent = resp.transcription;
} else {
  srtContent = JSON.stringify(resp);
}

const plainText = srtContent
  .replace(/^\d+\s*$/gm, '')
  .replace(/\d{2}:\d{2}:\d{2}[,\.]\d{3}\s*-->\s*\d{2}:\d{2}:\d{2}[,\.]\d{3}/gm, '')
  .replace(/\r?\n/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

return [{ json: { srtRaw: srtContent, srtText: plainText } }];

const original = $('02b - Gerar Protocolo3').item.json.body || {};
const protocolo = $('02b - Gerar Protocolo3').item.json.protocolo;

return [{
  json: {
    tipo: 'audio',
    texto_cidadao: $json.srtText || '',
    transcricao_srt: $json.srtRaw || '',
    from: original.from || '',
    name: original.name || original.pushName || '',
    lat: original.lat || null,
    lng: original.lng || null,
    mediaUrl: null,
    protocolo
  }
}];

const advertiserCode = $('02b - Gerar Protocolo3').first().json.protocolo;
const base64 = $input.first().json.data.base64;
const frame_name = $input.first().json.data.fileName;

return {
  json: { ...$json, fileName: `${frame_name}` },
  binary: {
    data: {
      data: base64,
      mimeType: 'image/jpeg',
      fileName: `${frame_name}`
    }
  },
  advertiserCode: advertiserCode
};

const original = $input.first().json.original || {};
const protocolo = $input.first().json.protocolo;
const Normalize = $input.first().json.normalize || {};

const mediaUrl = $input.first().json.mediaUrl || original.mediaUrl || null;

return [{
  json: {
    tipo: original.type || original.messageType || 'text',
    texto_cidadao: original.body
      || original.caption
      || original.text
      || Normalize.message?.conversation
      || Normalize.message?.extendedTextMessage?.text
      || '',
    transcricao_srt: null,
    from: original.from || '',
    name: original.name || Normalize.pushName || '',
    lat: original.lat || null,
    lng: original.lng || null,
    mediaUrl,
    protocolo
  }
}];

