const rawOutput = $input.first().json.output || $input.first().json.text || '';

let parsed;
try {
  const cleaned = rawOutput.replace(/\u0060\u0060\u0060json\n?/g, '').replace(/\u0060\u0060\u0060\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { valid: false, reason: 'parse_error', resposta_cidadao: 'Desculpe, houve um erro interno. Tente novamente.' };
}

return [{ json: { ...parsed, _rawAiOutput: rawOutput } }];

const ai = $('05 - Parse JSON da IA3').item.json;

if (ai.resposta_cidadao && ai.resposta_cidadao.trim() !== '') {
  return [{ json: { status: 'pending_info', message: ai.resposta_cidadao, ai_summary: ai.ai_summary } }];
}

const missing = ai.missing_fields || [];
const fieldLabels = {
  bairro: '📍 *Bairro* onde está o problema',
  rua: '🏠 *Rua ou Avenida* do problema',
  descricao: '📝 *Descrição do problema* (O que aconteceu?)'
};
const camposReais = missing.filter(f => fieldLabels[f]);
let missingList = camposReais.length > 0
  ? camposReais.map(f => fieldLabels[f]).join('\n')
  : '📍 *Endereço* (Rua e Bairro)\n📝 *Descrição do problema*';

let msg = `⚠️ *Recebemos seu relato!*\n\nMas precisamos de algumas informações:\n\n${missingList}\n\nResponda com essas informações! 😊`;

return [{ json: { status: 'pending_info', message: msg, ai_summary: ai.ai_summary } }];

const ai = $json;
const protoOriginal = $('02b - Gerar Protocolo3').item.json;

const protocoloFinal = protoOriginal.protocolo || ('ZEL-' + new Date().toISOString().slice(0,10).replace(/-/g,'') + '-' + Math.random().toString(36).substring(2,6).toUpperCase());

const severityMap = { critical: 'CRITICA', high: 'ALTA', medium: 'MEDIA', low: 'BAIXA' };
const categoriaMap = {
  vias: 'BURACO', iluminacao: 'ILUMINACAO', limpeza: 'LIXO',
  sinalizacao: 'OUTRO', arvores: 'ARVORE', drenagem: 'OUTRO',
  predios: 'OUTRO', outros: 'OUTRO'
};

const addressParts = (ai.address_guessed || '').split(',').map(s => s.trim());
const rua    = (addressParts[0] && addressParts[0] !== 'null') ? addressParts[0] : '';
const bairro = (addressParts[1] && addressParts[1] !== 'null') ? addressParts[1] : 'Nao informado';
const whatsapp = $('02b - Gerar Protocolo3').first().json.body.data.key.remoteJid.split('@')[0];

const midias = (ai.midias_acumuladas || []).map(url => ({ url, tipo: 'FOTO' }));

return [{
  json: {
    protocolo: protocoloFinal,
    categoria: categoriaMap[ai.category] || 'OUTRO',
    descricao: ai.ai_summary || '',
    criticidade: severityMap[ai.severity] || 'MEDIA',
    rua, bairro,
    cidade: 'peruibe',
    latitude:  (ai.lat && ai.lat !== 'null')  ? Number(ai.lat) : null,
    longitude: (ai.lng && ai.lng !== 'null') ? Number(ai.lng) : null,
    cidadao: {
      nome:     $('01 - Webhook WhatsApp3').first().json.body.data.pushName || 'Cidadao WhatsApp',
      telefone: whatsapp || '',
      anonimo:  false
    },
    midias
  }
}];

